module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:1] carry;
assign carry[1] = A[1] & B[1];
assign S[1] = A[1] ^ B[1] ^ carry[1];

genvar i;
generate
    for (i = 2; i <= 32; i = i + 1) begin
        assign carry[i] = A[i] & B[i] | (A[i] ^ B[i]) & carry[i-1];
        assign S[i] = A[i] ^ B[i] ^ carry[i-1];
    end
endgenerate

assign C32 = carry[32];

endmodule
